--------------------------------------------------------------------------------
-- מערכת תיעוד הזמנות טיסות (ארקיע) · install_ui.sql
-- מגיש את אפליקציית ה-HTML (bookings/app/index.html) ישירות מ-ORDS,
-- כך שהיא נפתחת בכתובת אחת (אותו מקור כמו ה-API — ללא CORS, ללא אחסון מקומי).
--
-- להרצה בסכמת ARKIA (Database Actions → SQL), F5. דורש: install_api.sql הותקן.
-- כתובת האפליקציה אחרי ההרצה:  /ords/arkia/api/app
--
-- נוצר אוטומטית מ-bookings/app/index.html (base64). לעדכון UI: הריצו מחדש.
--------------------------------------------------------------------------------

BEGIN EXECUTE IMMEDIATE 'DROP TABLE api_app CASCADE CONSTRAINTS PURGE'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
CREATE TABLE api_app (id NUMBER PRIMARY KEY, b64 CLOB);
INSERT INTO api_app (id, b64) VALUES (1, EMPTY_CLOB());
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
UPDATE api_app SET b64 = b64 || '' WHERE id = 1;
COMMIT;

BEGIN
  BEGIN ORDS.DEFINE_TEMPLATE(p_module_name => 'arkia.api', p_pattern => 'app'); EXCEPTION WHEN OTHERS THEN NULL; END;
  BEGIN
    ORDS.DEFINE_HANDLER(
      p_module_name => 'arkia.api',
      p_pattern     => 'app',
      p_method      => 'GET',
      p_source_type => ORDS.source_type_media,
      p_source      => q'~SELECT 'text/html; charset=utf-8' AS content_type, APEX_WEB_SERVICE.CLOBBASE642BLOB(b64) AS content FROM api_app WHERE id = 1~');
  EXCEPTION WHEN OTHERS THEN NULL;
  END;
  COMMIT;
END;
/
